import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the input length does not exceed the buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        // Use StringBuilder to safely copy user input into a resizable buffer
        StringBuilder buffer = new StringBuilder();

        // Copy user input into the buffer
        for (int i = 0; i < name.length(); i++) {
            buffer.append(name.charAt(i));
        }

        System.out.println("Hello, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
